<section class="bg-[var(--color-bg)]">
    <div class="mx-auto w-[92%] sm:w-[90%] md:w-[88%] lg:w-[85%] py-12 md:py-16">
        <h1 class="text-3xl md:text-4xl font-extrabold tracking-tight text-[var(--color-text)]">Returns & Warranty</h1>
        <p class="mt-3 text-[var(--color-muted)] max-w-2xl">We want you to be happy with every purchase. Here's how our return and warranty process works.</p>

        <div class="mt-10 grid gap-6 md:grid-cols-2">
            <div class="rounded-[var(--radius-card)] border border-[var(--color-border)] bg-[var(--color-surface)] p-6">
                <h2 class="text-lg font-bold text-[var(--color-text)] mb-4">30-Day Returns</h2>
                <ul class="space-y-3 text-sm text-[var(--color-muted)]">
                    <li class="flex items-start gap-2"><span class="text-[var(--color-accent)] font-bold">1.</span> Initiate your return from your account or <a href="/contact" class="text-[var(--color-accent)] hover:underline">contact us</a>.</li>
                    <li class="flex items-start gap-2"><span class="text-[var(--color-accent)] font-bold">2.</span> Receive a prepaid return shipping label via email.</li>
                    <li class="flex items-start gap-2"><span class="text-[var(--color-accent)] font-bold">3.</span> Pack the item in its original packaging and ship it back.</li>
                    <li class="flex items-start gap-2"><span class="text-[var(--color-accent)] font-bold">4.</span> Refund processed within 3-5 business days of receiving the item.</li>
                </ul>
                <div class="mt-4 rounded-lg bg-[var(--color-bg)] p-3 text-sm text-[var(--color-muted)]">
                    <strong class="text-[var(--color-text)]">Conditions:</strong> Items must be unused, in original packaging, with all accessories included. Sale items are eligible for store credit only.
                </div>
            </div>

            <div class="rounded-[var(--radius-card)] border border-[var(--color-border)] bg-[var(--color-surface)] p-6">
                <h2 class="text-lg font-bold text-[var(--color-text)] mb-4">Warranty Coverage</h2>
                <ul class="space-y-3 text-sm text-[var(--color-muted)]">
                    <li class="flex items-start gap-2"><span class="text-[var(--color-accent)]">&#10003;</span> <strong class="text-[var(--color-text)]">Standard warranty:</strong> 12 months on all products covering manufacturing defects.</li>
                    <li class="flex items-start gap-2"><span class="text-[var(--color-accent)]">&#10003;</span> <strong class="text-[var(--color-text)]">Extended warranty:</strong> Available on select products for up to 24 months.</li>
                    <li class="flex items-start gap-2"><span class="text-[var(--color-accent)]">&#10003;</span> <strong class="text-[var(--color-text)]">Claim process:</strong> Contact support with your order number and issue description.</li>
                    <li class="flex items-start gap-2"><span class="text-[var(--color-accent)]">&#10003;</span> <strong class="text-[var(--color-text)]">Resolution:</strong> Repair, replacement, or refund at our discretion.</li>
                </ul>
                <div class="mt-4 rounded-lg bg-[var(--color-bg)] p-3 text-sm text-[var(--color-muted)]">
                    <strong class="text-[var(--color-text)]">Not covered:</strong> Physical damage, water damage, unauthorized modifications, or normal wear and tear. See <a href="/warranty-exclusions" class="text-[var(--color-accent)] hover:underline">full exclusions</a>.
                </div>
            </div>
        </div>

        <div class="mt-8 flex flex-wrap gap-3">
            <a href="/returns-decision-tree" class="inline-flex h-10 items-center gap-2 rounded-[var(--radius-button)] border border-[var(--color-border)] bg-[var(--color-surface)] px-5 text-sm font-semibold text-[var(--color-text)] transition hover:border-[var(--color-accent)] hover:text-[var(--color-accent)]">Returns Decision Tree</a>
            <a href="/warranty-claim" class="inline-flex h-10 items-center gap-2 rounded-[var(--radius-button)] border border-[var(--color-border)] bg-[var(--color-surface)] px-5 text-sm font-semibold text-[var(--color-text)] transition hover:border-[var(--color-accent)] hover:text-[var(--color-accent)]">Warranty Claim Checklist</a>
        </div>
    </div>
</section>
